            g.nodes.Add(new DialogueNode { id = "cal_deal_ok", speaker = "Calloway", text = "*(He tells you — he *promised* face-up, and Calloway's word is the one thing in the house that isn't for sale — and the worst of it is bad but bounded: the favor could cost you a *choice* down the road, a moment where he asks you to look the other way, or carry a message, or not be where you said you'd be. Real, but survivable. You shake on it, eyes open.)* …*there.* …*see?* not so *terrible* — a *leash*, *yes*, but a *long* one, and i'll not *jerk* it for *spite*, spite's *unprofitable.* *(he marks you down with a flourish)* …*pleasure* doing *business*, cold one. you *haggled* *honest* and i *dealt* *honest* and *that*, in this *grey* *swindle*, is *practically* a *wedding.* …*(he slides the marker to you)* …the *door's* *yours* when you *need* it. …and *someday* …i'll *come* *collecting*, and you'll *grumble*, and *pay*, because you're a *soul* of your *word* — i can *smell* it, it's *why* i *like* you — …and we'll *both* *know* the *deal* was *fair.* …*fair's* the *whole* *racket*, friend. …*nobody* *expects* …the *house* …to be *fair.*", onEnter = new[] { new FlagClause { key = "cal.haggled", op = FlagOp.SetTrue }, new FlagClause { key = "cal.struck_deal", op = FlagOp.SetTrue }, new FlagClause { key = "cal.owes_calloway", op = FlagOp.SetTrue }, new FlagClause { key = "disp.cunning", op = FlagOp.AddInt, amount = 1 } } });
