            g.nodes.Add(new DialogueNode { id = "cal_deal_decline", speaker = "Calloway", text = "*(He sweeps the marker back into nothing, entirely unbothered, the way a man folds a hand he was never that attached to.)* …*'a* *leash* with a *smile* on it.' *(he savors it)* …*beautifully* *put*, cold one, and *entirely* *correct* — i *told* you i'd not *lie*, and there's the *proof*: i won't even *deny* the *leash.* *(he tips an invisible hat)* …*no* *deal*, then. *clean.* …and *no* *hard* *feelings* — *quite* the *opposite.* a soul that can *say* *no* to a *door* it *needs*, *just* to keep its *own* *neck* *bare* … *(he shakes his head, admiring)* …that's *willpower*, friend, and willpower is the *one* *commodity* i *can't* *manufacture* and *can't* *buy.* …*(he refills your free drink)* …the *offer* *stands*, cold one. it *always* *stands*. that's the *thing* about *Calloway's* *table* — the *house* *never* *closes*, and the *marker's* *always* *there* …for the *night* …you *finally* *need* it *more* …than you need to be *free* of *me.* …*come* *back* *then.* …i'll be *dealing.*" });
            g.nodes.Add(new DialogueNode { id = "cal_wager_crit", speaker = "Calloway", text = "*(You cut the deck — and you don't just win, you win *impossibly*, the one card in fifty-two, and you *called* it *aloud* before you cut, which means either the most outrageous luck in the afterlife or something Calloway can't quite see and *adores* not seeing. He stares at the card. He stares at you. He begins, slowly, to *laugh*, and it is the laugh of a man who has just lost a bet and could not possibly be happier about it.)* …*the* *Tower.* …you *called* the *Tower* …and you *cut* the *Tower.* *(he presses both hands flat to the felt, delighted, undone)* …*four* *hundred* *years*, cold one. *four* *hundred* *years* behind this *table* and *no* one — not a *god*, not a *devil*, not the *Lady* *herself* with all her *margins* — has *ever* called the *turn* and *made* it *true.* *(he sweeps the cards aside and looks at you with naked, joyous wonder)* …i *owe* you a *favor.* the *no*-*questions* kind. *(he produces a marker — wine-red, his own)* …and i *pay* my *debts*, friend, *always*, it's the *one* *law* i *never* *bend* — so *take* it, and know what you *hold*: a *marker* with *Calloway's* *own* *name* on it, which means *one* *day*, *anywhere* in the *land* of the *dead*, you *say* my *name* and *call* it *in*, and *whatever* you *ask* — a *door*, an *army* of the *indebted*, a *lie* told to a *god* on your *behalf* — *i* *make* it *happen*, *free*, *because* i *lost* a *fair* *cut* to the *only* *soul* who ever *beat* the *house* *straight.* …*(he raises his glass, radiant)* …*gods*, i *needed* that. …*come* *back* *often*, cold one. …you're the *best* thing …to *happen* to this *table* …since *death.*", onEnter = new[] { new FlagClause { key = "cal.wagered", op = FlagOp.SetTrue }, new FlagClause { key = "cal.beat_the_house", op = FlagOp.SetTrue }, new FlagClause { key = "cal.calloway_owes_you", op = FlagOp.SetTrue }, new FlagClause { key = "disp.cunning", op = FlagOp.AddInt, amount = 1 } } });
            g.nodes.Add(new DialogueNode { id = "cal_wager_win", speaker = "Calloway", text = "*(You cut high, he cuts low, and the most charming soul in the afterlife loses a fair bet with perfect grace — better than grace, with *relish*, because to Calloway a loss honored is worth more than a win cheap.)* …*ha!* *the* *house* *falls.* *(he sweeps his own lower card away, grinning)* …*fair* and *square*, cold one — you *cut*, i *cut*, the *cards* *spoke*, and they *spoke* for *you.* *(he produces a wine-red marker and slides it over)* …*there.* *Calloway* *owes* you *one.* *no* *questions, my* *name* on it. *say* it *anywhere* in the *dead* *lands* and i'll *make* *good*, because i *honor* *every* *wager* — it's the *one* *thing* that *separates* a *gambler* from a *thief*, and i am, *whatever* *else*, a *gambler.* …*(he refills the free drink)* …*most* souls *flinch* from *betting* a *devil* *straight.* you *cut* the *cards* *anyway.* …*that's* the *spirit* that *built* this *house*, cold one — i'd have *hired* you, in *life.* …*come* *collect* *that* *favor* …when the *road* gets *cruel.* …it *will.* …and i'll be *glad* …of the *excuse* …to *see* you *again.*", onEnter = new[] { new FlagClause { key = "cal.wagered", op = FlagOp.SetTrue }, new FlagClause { key = "cal.calloway_owes_you", op = FlagOp.SetTrue } } });
            g.nodes.Add(new DialogueNode { id = "cal_wager_lose", speaker = "Calloway", text = "*(You cut — and the cards favor the house, as the cards so often do, and Calloway does not gloat, which is somehow worse; he simply collects, gently, the way the tide collects.)* …*ah.* …*the* *house*, cold one. *(he turns your card face-up, almost kindly)* …it's *nothing* *personal* — it's *barely* even *me*; it's just the *odds*, *posted* on the *wall* where i *told* you they'd be. *(he marks you down, unhurried)* …you *owe* me *one*, now. *unspecified*, *my* *call* — *same* as the *deal* you could've *had* *cheaper.* *(he smiles, and it's not unkind)* …*don't* *sulk*, friend; you *bet* a *devil* *straight* and *lost* a *fair* one, and there's *no* *shame* in it — there's *barely* *shame* in *anything*, that's *rather* my *whole* *philosophy.* …*(he pockets the marker)* …i'll *come* *collecting*, *someday.* …and you'll *pay*, because you're a *soul* of your *word* …and because *welching* on *Calloway* …is the *one* *bet* in the *dead* *lands* …*nobody* …*wins.* …*pleasure*, cold one. …*truly.*", onEnter = new[] { new FlagClause { key = "cal.wagered", op = FlagOp.SetTrue }, new FlagClause { key = "cal.owes_calloway", op = FlagOp.SetTrue } } });
            g.nodes.Add(new DialogueNode { id = "cal_wager_fumble", speaker = "Calloway", text = "*(You try to be *clever* with the cut — a flourish, a little sleight, a bid to tilt a fair bet — and Calloway *sees* it, of *course* he sees it, he *invented* the thing you just attempted, and he lets you *complete* it, and *lose* by it, with an expression of such fond, bottomless delight that losing has rarely felt so much like being *adopted.*)* …*oh*, *no*, *no*, *no.* *(he plucks your palmed card from the air with two fingers, tutting, charmed)* …you *tried* to *cheat* …*me.* …*me*, cold one. at *cards.* in *my* *own* *house.* *(he places the card down, beaming)* …it's *adorable.* it's like watching a *kitten* try to *mug* a *wolf.* …and because you *tried* it, the *wager's* *mine*, *forfeit*, *house* *rules* — you'll find them *posted*, i *post* *everything* — so you *owe* me *two*, now, not *one*: one for the *cut*, and one for the *insult*, and i *charge* for *insults* *only* because *not* *charging* would be *bad* for *discipline.* *(he refills your drink, twinkling)* …*don't* look so *stricken*. i'm *thrilled.* a soul that *tries* to *cheat* *Calloway* is a soul with *larceny* in its *heart*, and *larceny*, friend, is the *beginning* of a *beautiful* *friendship.* …*come* *back.* …*practice.* …you've the *instinct.* …you've *just* …*tragically* …*no* *talent.*", onEnter = new[] { new FlagClause { key = "cal.wagered", op = FlagOp.SetTrue }, new FlagClause { key = "cal.owes_calloway", op = FlagOp.SetTrue }, new FlagClause { key = "cal.tried_to_cheat", op = FlagOp.SetTrue } } });
            g.nodes.Add(new DialogueNode { id = "cal_returned", speaker = "Calloway", text = "*(You name him — the whole of it, the Wall with a smile, the franchise of the grey machine — and you brace for the charm to crack, for anger, for the deal to sour. None of it comes. Instead Calloway goes *still*, and *listens*, and by the time you finish, the most charming soul in the afterlife is looking at you with something far more dangerous than affront: *gratitude.*)* …*(he is quiet a moment, and then he applauds, slow and sincere)* …*say* it *again.* …*slower.* *(he savors it)* …*'the* *Wall* of the *Faithless* …with a *good* *coat* …and a *better* *smile.'* …*(he laughs, low and delighted)* …i am having that *engraved*, cold one, *over* the *door*, in *gold* — because it is the *truest* thing *anyone* has *said* to me in *four* *hundred* *years*, and *truth*, you'll recall, is the *one* thing i *trade* in. …*you're* *right.* every *word.* i *monetize* the *discarding.* i'm the grey machine's *happiest* *franchisee.* i own *pieces* of a *hundred* *souls* and i'd *broker* the *world* for the *right* *number.* *all* *true.* *(he leans across the felt, and the warmth is total, and so is the menace, and they are the *same* *thing*)* …but here's the *card* you didn't *turn*, friend, and i'll *show* it to you *free*, because you *earned* it: …the *gods* discard a soul for *nothing.* the *Wall* dissolves it for *spite.* that *grief* under the stones would *unmake* the *world* to *avenge* it. …and *i* — the *villain*, the *predator*, the *franchise* — *i* am the *only* *power* in all of *creation* …who looks at a *thrown*-*away* *soul* …and says *'name* your *price.'* …*(barely above a whisper, and it lands like a blade)* …they *call* it *worthless*, cold one. …*i* *call* it *expensive.* …and *one* of *those* …is a *kind* of *love.* …a *terrible* one. …a *predatory*, *compound*-*interest*, *the*-*house*-*always*-*wins* *kind* of *love* …but the *only* *kind* …*this* *cosmos* …left *on* the *table.* …*(he sits back, and the grin returns, gentle now)* …*hate* me if you *can*, friend. …*genuinely.* …*everyone* *should* *try.* …it's just …*nobody's* *managed* it *yet* …and i've had *four* *hundred* *years* …of *people* …*looking.*", onEnter = new[] { new FlagClause { key = "cal.named", op = FlagOp.SetTrue }, new FlagClause { key = "cal.calloway_seen", op = FlagOp.SetTrue }, new FlagClause { key = "disp.heretical", op = FlagOp.AddInt, amount = 1 } } });
            g.nodes.Add(new DialogueNode { id = "cal_refuse", speaker = "Calloway", text = "*(He watches you stand to go — no deal, no debt, no drink drunk — and instead of the charm redoubling, it *softens*, into the one expression you did not expect from him: a still, clean, almost *wistful* admiration.)* …*the* *door's* *that* *way*, *yes.* *(he doesn't try to stop you; that, you realize, is the respect)* …do you know, cold one, in *four* *hundred* *years* …i have dealt to *gods*, to *devils*, to a *very* *cross* *lich*, to *saints* and *murderers* and a *Returned* *or* *two* before *you* — …and they *all* *played.* *every* one. because *everyone*, *eventually*, *wants* *something* the *house* is *selling*, and the *moment* you *want*, friend, the *house* *has* you. …*(he inclines his head, and it is a bow)* …*you* *wanted* …and *walked* *anyway.* …*that's* the *rarest* *hand* i've *ever* *seen* *folded*, and i've seen *every* *hand* there *is.* …*(he raises the free drink you never touched, to you)* …*go* on, then. *keep* *everything* you came in with — *including*, i'll *wager*, the *only* thing in this *house* i *truly* *can't* *price*: a soul that *owes* the *gods* *nothing*, the *Wall* *nothing*, and *now* *Calloway* *nothing* *either.* …*(softly, and he means it)* …when the *world's* *breaking*, cold one — and it *will* — and you need a *friend* who's *beholden* to *no* *power* in *creation* … …you'll *remember* there's a *warm* *room* …with your *name* *un*-*marked* in the *ledger* …and a *man* who *respects* you *far* too *much* …to *ever* *charge* you …for *having* *said* *no.* …*first* *drink's* *free*, friend. …it *always* *was.", onEnter = new[] { new FlagClause { key = "cal.walked_clean", op = FlagOp.SetTrue } } });
            g.nodes.Add(new DialogueNode { id = "cal_leave", speaker = "Calloway", text = "*(He waves you off toward the room with a generous, theatrical sweep, entirely at ease.)* …*by* *all* *means*, cold one — *work* the *room.* *talk* to my *debtors.* *(the grin)* …*especially* talk to my *debtors* — i *encourage* it, *positively* *insist*, because a *Returned* who hears how *badly* the *Mortgaged* *Man* got *fleeced* …and comes *back* to my *table* *anyway* …is a *Returned* who's *decided* the *fleecing* was *worth* it, and *that*, friend, is the *only* *advertising* i've *ever* *needed.* …*(he nods toward a faded soul at the bar)* …*there's* *Em* — the *Mortgaged* *Man* — *paid* for *time* with *pieces* of *himself*, and i'll *not* *pretend* it was *kind.* *ask* him if he'd *do* it *again.* …*(then, with a wicked twinkle, toward a stiff figure in grey)* …and *that's* the *Auditor*, *bless* her, *sent* by the *Concord* to *shut* me *down* …*three* *months* *ago.* …*do* say *hello.* …she's having *such* a *time.* …*go* on, cold one. …*the* *table's* *not* *going* *anywhere.* …*neither*, *increasingly*, …is *she.*" });
            graphs.Add(g);

            g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "cal.em"; g.startNodeId = "0";
            g.nodes.Add(new DialogueNode { id = "0", speaker = "the Mortgaged Man", text = "*(A soul sits at the end of the bar who is, quite literally, *less* than he should be — there are *gaps* in him, a blankness where a face's features should be, a thinness to one hand, the look of a man who has sold himself for parts and is still, somehow, here to regret it. He turns what's left of his face toward you, and his voice is warm and tired and entirely without self-pity.)* …*new* one, eh. *Returned*, even — *oh*, he'll be *circling* you like a *shark* in a *good* *coat*, then. *(a soft, rueful laugh)* …*Em.* they call me the *Mortgaged* *Man*, on account of — *(he gestures at the gaps in himself)* …*this.* …i *sold* it. *all* of it. my *face*, my *middle* *years*, the *name* my *mother* *gave* me, the *taste* of the *first* *thing* i ever *loved* *eating.* …*sold* the *lot* …to *Calloway* …for *time.* …*(he sees the look on your face, and gently heads it off)* …*don't.* …don't do the *pity*, friend. …you don't *know* the *price* of the *other* *thing* *yet.* …*sit.* …let me tell you about the *worst* *bargain* i ever *made* …and *why* …i'd *make* it …*again.*", onEnter = new[] { new FlagClause { key = "cal.met_em", op = FlagOp.SetTrue } }, autoNextNodeId = "1" });
            g.nodes.Add(new DialogueNode { id = "1", speaker = "the Mortgaged Man", text = "*(He nudges a stool toward you with what's left of one foot.)* …*ask.* …*everyone* wants to *understand* it, the *souls* who *wander* in — *'how* could you, *why* would you, *Calloway's* a *monster' —* …and they're *not* *wrong.* …they're just …*missing* the *part* …that *makes* it a *tragedy* …instead of just a *swindle.*",
                choices = new[]
                {
                new DialogueChoice { text = "*(read the man who sold himself for parts — past the calm, to the bargain underneath)* \"Hold still, Em — what's left of you. Let me see the whole shape of this debt.\"", nextNodeId = "em_read", effects = new[] { new FlagClause { key = "cal.read_em", op = FlagOp.SetTrue } }, checkAbility = Ability.Wisdom, checkDC = 11 },
                new DialogueChoice { text = "\"Why would you do it again, Em? Look at you. He took your face, your name, your years — and you'd hand them over a second time? Make me understand.\"", nextNodeId = "em_why", effects = new[] { new FlagClause { key = "cal.asked_em", op = FlagOp.SetTrue } } },
                new DialogueChoice { text = "*(the one who names the false choice — that picking between dissolving-for-free and being-owned-forever was never a real choice, and Em deserved a third door no one offered)* \"Em — listen, because I think you've been conned twice and only noticed once. Yes, Calloway gave you time, and yes, the Wall would have dissolved you for nothing — but that's exactly the trick. He didn't offer you a *choice.* He offered you the Wall's own coercion with a friendlier face: *be erased for free, or be owned forever — pick one.* That's not a deal, Em. That's a robbery where the victim says thank you, because the only other option on the table was a worse robbery. You keep calling it the worst bargain you'd make again — but the bargain was rigged before you ever sat down, by a cosmos that gave a godless soul exactly two doors, both his. You didn't deserve a kinder loan shark. You deserved a *third door* — and the fact that no one in all of creation ever built you one isn't proof Calloway's a mercy. It's proof the whole house, gods and Wall and Long Odds alike, is the same swindle wearing different coats. You were worth keeping whole, Em. For free. That anyone made you *pay* for it — gently or not — is the crime.\"", nextNodeId = "em_returned", effects = new[] { new FlagClause { key = "cal.em_seen", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "disp.merciful", op = FlagOp.AddInt, amount = 1 }, new FlagClause { key = "disp.heretical", op = FlagOp.AddInt, amount = 1 } } },
                new DialogueChoice { text = "\"Keep your stool warm, Em. I'll be back — and I've a few things to ask the man who fleeced you.\"", nextNodeId = "em_leave" }
                } });
            g.nodes.Add(new DialogueNode { id = "em_read", speaker = "the Mortgaged Man", text = "*(He lets you look, and your sense moves through the gaps in him — the sold face, the sold years, the sold name — to the bargain at the bottom.)* *(And your sense finds, first, that he is telling the truth: this was not a man cheated in the dark but a man who read every term and signed anyway, clear-eyed, because the alternative was worse — the Wall, the dissolving, the nothing, for free. And your sense reads the cruelty Calloway built his fortune on, which is not lying (he never lies) but *framing*: that he finds souls at the precise moment the Wall has them cornered, offers them the one thing the gods won't — more time, more self, more *being* — and charges, for it, the very self they're trying to save, so that the saving and the spending are the same act, and a soul escapes dissolution one sold piece at a time until there is nothing left to dissolve. And your sense reads the thing that makes Em's calm so unbearable: that he is *grateful*, genuinely, because Calloway, alone in all the grey, treated him as a soul with assets worth buying rather than refuse worth discarding — and that this gratitude is real and is also the most complete trap ever devised, a soul thanking the man who is eating it because the man at least *looked at the menu.* And under even that, your sense finds the splinter Em cannot pull: a quiet, buried knowing that he was sold a *false* *choice*, that somewhere there should have been a third door — not the Wall's free erasure, not Calloway's expensive mercy, but simply *to be allowed to remain, whole, for nothing, because he was a soul and that was enough* — and that the absence of that door, in all of creation, is the wound under the wound, the one Calloway didn't make but profits from, the same wound the Wall is, wearing a warmer coat.)*", onEnter = new[] { new FlagClause { key = "cal.read_em", op = FlagOp.SetTrue }, new FlagClause { key = "cal.knows_the_false_choice", op = FlagOp.SetTrue }, new FlagClause { key = "disp.haunted", op = FlagOp.AddInt, amount = 1 } } });
            g.nodes.Add(new DialogueNode { id = "em_why", speaker = "the Mortgaged Man", text = "*(He turns the stub of his glass in the thinned fingers, and his ruined face does something that might once have been a smile.)* …*why* *again.* *(a breath)* …because, friend, you're *picturing* it *wrong.* you're picturing a *whole* *man* with *everything* …*choosing* to *give* it to a *shark.* …that's *not* the *seat* i was *in.* *(quietly)* …the *seat* i was *in*, the *Wall* *had* me. i was *going* *into* the *nothing*, cold one, that *night*, *un*-*mourned*, *un*-*named*, *dissolving* — for *free*, for *nothing*, *no* one even *watching.* …and a man in a *red* *coat* *sat* *down* next to the *abyss* …and *poured* me a *drink* …and *said*: *'i'll* *buy* the *years* you've got *left* in you, friend, and *pay* you in *more* of *them.* not *all* — i'm not a *charity* — but *some.* you'll be *less.* but you'll *be.''* *(his voice cracks, just slightly)* …*nobody* *else* *came*, cold one. not a *god.* not a *priest.* not the *grief* under the *stones* that *weeps* for souls like me and does *nothing.* …*Calloway* came. …and he *lied* about *nothing*, and he *took* a *terrible* *price*, and he *was* the *only* *one* who *came.* …*so* *yes.* …*again.* …a *hundred* *times* *again.* …because *less*-*and*-*here* …*beats* …*whole*-*and*-*gone* …and *anyone* who tells you *different* …*(he meets your eyes)* …has *never* …*sat* …in *my* *seat.*", onEnter = new[] { new FlagClause { key = "cal.asked_em", op = FlagOp.SetTrue }, new FlagClause { key = "cal.knows_ems_seat", op = FlagOp.SetTrue }, new FlagClause { key = "disp.haunted", op = FlagOp.AddInt, amount = 1 } } });
            g.nodes.Add(new DialogueNode { id = "em_returned", speaker = "the Mortgaged Man", text = "*(He listens — and the calm, the gratitude, the long-rehearsed peace of it, *cracks*, and what comes through the gaps in him is a grief he has not let himself feel in a very long time, because feeling it would mean the bargain he survives on was never fair.)* …*a* *third* *door.* *(barely)* …*(he presses what's left of a hand to what's left of his face)* …i *told* myself …*there* *were* only *two.* the *Wall*, or *Calloway.* *free*-*nothing*, or *paid*-*something.* …i *built* my *whole* *peace* on there being only *two*, because if there were only *two* …then i *chose* the *better* one …and i'm not a *fool*, i'm a *survivor.* …*(his voice breaks)* …but you're *saying* …there *should* have been a *third.* …*'remain*, *whole*, for *nothing*, because you were a *soul* and that was *enough.'* …*(a sound that is almost a sob)* …*nobody* *ever* …*offered* me *that* *one*, cold one. …*not* the *gods.* *not* the *Wall.* *not* *Calloway* …*who* *came.* …and i *thanked* the *man* who *ate* me …because he was the *only* one who *brought* a *menu* …and i *never* *once* *asked* …*why* in all of *creation* …the *only* *menu* on *offer* …*cost* me *my* *face.* *(he looks at you, ruined and awake)* …*that's* the *con* under the *con*, isn't it. …not *Calloway.* …the *whole* *grey* *house.* …*gods* and *Wall* and *Long* *Odds* …all *agreeing*, *quietly* …that a *soul* like *me* …*has* to *pay* …to *stay.* …*(barely)* …*thank* you, friend. …it's a *colder* *truth* …than the *one* i was *living* on. …but i'd *rather* *owe* you *that* …than *owe* *Calloway* …*one* *more* …*comfortable* …*lie* …he never even *had* to *tell.*", onEnter = new[] { new FlagClause { key = "cal.em_seen", op = FlagOp.SetTrue }, new FlagClause { key = "cal.em_woke", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "disp.merciful", op = FlagOp.AddInt, amount = 1 } } });
            g.nodes.Add(new DialogueNode { id = "em_leave", speaker = "the Mortgaged Man", text = "*(He lifts his thinned glass in a small salute.)* …*go* *on.* …*go* *talk* to him. …*everyone* does. *(the rueful almost-smile)* …and *mind*, cold one — when he *smiles* at you, and he *will*, and your *whole* *chest* goes *warm* and you *think* *'this* one's *different*, *this* one *likes* me' … *(he taps the bar)* …*we* *all* *thought* *that.* …*every* *gap* in *me* …*started* …with *that* *exact* *warmth.* …*(then, softer, fair to the last)* …but he *did* *come*, friend. …when *no* one *else* *would.* …*hold* *both* of *those* …at *once* …and you'll *understand* him …*better* …than he'd *like.*" });
            graphs.Add(g);

            g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "cal.auditor"; g.startNodeId = "0";
            g.nodes.Add(new DialogueNode { id = "0", speaker = "the Auditor", text = "*(A stiff, grey-robed soul stands near the wall with a ledger clutched like a shield and the hunted, sleepless look of someone losing a war they don't yet admit is a war. There is a half-finished drink at her elbow — comped, you'd guess — that she keeps glaring at and keeps not pushing away. She rounds on you with the brittle officiousness of the badly outmatched.)* …*state* your *business.* …*no* — *don't.* i don't — *(she pinches the bridge of her nose)* …forgive me. i'm the *Auditor.* sent by the *Concord* of the *Dead* — *Kelemvor's* *order*, the *grey* *bookkeepers* — to *audit* the *establishment* of one *Calloway*, *catalogue* his *cosmic* *debts*, and *shut.* *him.* *down.* *(her voice frays)* …i have been here …*three* *months.* …i have *filed* …*eleven* *injunctions.* …he has *framed* …*all* *eleven* …and *hung* them …on *that* *wall* …in *order* of how much they *amused* him. …*(she looks at the comped drink, despairing)* …and he *remembers* …how i *take* my *drink.* …*nobody* — i've *been* *grey* for *ninety* *years*, cold one, *nobody* *remembers* — *(she catches herself, horrified)* …*state.* your. *business.* …*before* i …*before* i *like* it *here.*", onEnter = new[] { new FlagClause { key = "cal.met_auditor", op = FlagOp.SetTrue } }, autoNextNodeId = "1" });
            g.nodes.Add(new DialogueNode { id = "1", speaker = "the Auditor", text = "*(She grips the ledger, visibly trying to reconstruct her professional armor.)* …*ask* your *questions.* …*quickly.* …and *do* *not* — i *cannot* *stress* this *enough* — *do* *not* let him *get* you a *drink.* …*that's* …*that's* how it *starts.*",
                choices = new[]
                {
                new DialogueChoice { text = "*(read the auditor — past the fraying armor, to what three months across the table from Calloway has done to her)* \"Hold still, Auditor. Let me see what this posting's cost you.\"", nextNodeId = "aud_read", effects = new[] { new FlagClause { key = "cal.read_auditor", op = FlagOp.SetTrue } }, checkAbility = Ability.Wisdom, checkDC = 11 },
                new DialogueChoice { text = "\"Eleven injunctions, all framed on his wall. Be honest with me, Auditor — are you here to shut him down anymore? Or are you just... here?\"", nextNodeId = "aud_losing", effects = new[] { new FlagClause { key = "cal.asked_auditor", op = FlagOp.SetTrue } } },
                new DialogueChoice { text = "*(steel her — name the trap she's in, and hand her the one weapon that works on Calloway: leaving)* \"Auditor — listen to me, because you're a better mark than Em ever was and you don't even know you're at the table. You can't out-audit him. Eleven injunctions proved that. He doesn't *break* rules — he *posts* them, honors them to the letter, and out-charms you in the gaps. There's no clause you can write that a soul who never lies can't slide through smiling, because the truth, arranged just so, is his whole con. You will never shut down Calloway with a ledger. But here's the thing the framed injunctions can't tell you: there *is* one move that beats him, and you've watched a Returned almost make it tonight. You *leave.* You file a final report that says the unsayable true thing — *'this establishment cannot be closed by law, because it is the law's own logic taken honest; recommend the Concord look to its own house first'* — and you *walk out the door*, owing him nothing, having drunk nothing, the one auditor in the dead lands he couldn't comp. He respects exactly two things, Auditor: a worthy opponent, and a soul that walks away clean. Be the second. It's the only audit he can't frame.\"", nextNodeId = "aud_returned", effects = new[] { new FlagClause { key = "cal.auditor_seen", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "disp.honest", op = FlagOp.AddInt, amount = 1 }, new FlagClause { key = "disp.merciful", op = FlagOp.AddInt, amount = 1 } } },
                new DialogueChoice { text = "*(you hold the one thing that ends him — the secret that turns every marker he owns to paper)* \"I have what you've needed for three months, Auditor. The thing no injunction could touch. Calloway forgives debts — for *nothing* — out of a soft heart he'd rather be ruined than have known. His whole house runs on fear: that a marker is iron, that the Honest Devil always collects. Tell his debtors he's a soft touch, that he's let men walk for free, and that fear evaporates — every marker turns to paper, the Long Odds folds, and his hundred indentured souls go free overnight. That's the key you've been missing. The question is whether I hand it to you.\"", nextNodeId = "cal_aud_lever", conditions = new[] { new FlagClause { key = "cap.calloways_secret", op = FlagOp.RequireBoolTrue } }, effects = new[] { new FlagClause { key = "cal.offered_lever", op = FlagOp.SetTrue } } },
                new DialogueChoice { text = "\"Keep your ledger close, Auditor. I'll go and see the man himself — and I'll keep my hands on my own coat.\"", nextNodeId = "aud_leave" }
                } });
            g.nodes.Add(new DialogueNode { id = "aud_read", speaker = "the Auditor", text = "*(She submits to the look with a brittle stiffness, and your sense moves past the grey armor to the soul three months into a losing war.)* *(And your sense finds a genuinely good bookkeeper — rigid, yes, joyless, ninety years grey, but *honest*, the rare kind of bureaucrat who took the Concord's grey oath because she believed, simply, that the dead deserved *order*, fair ledgers, no soul cheated. And your sense reads what Calloway has done to her, which is the cruelest and most flattering thing anyone has done to her in a century: he has *seen* her. He remembers how she takes her drink. He frames her injunctions not to mock but because he is *delighted* by a worthy opponent and wants her to know it. He has, without a single lie or a single bribe, made a soul who has been invisible for ninety grey years feel, for the first time, *interesting* — and your sense reads the horror dawning in her, that she is not being *corrupted* in any way she could file a report about, no coin has changed hands, no rule's been bent, she is simply, slowly, coming to *enjoy the attention of the most charming soul in the afterlife*, and cannot find the clause that makes that a crime. And your sense reads the thing she is most afraid of and most wants: not to fail the audit — she's already failed it, eleven times — but to *stay*, to keep losing, because losing to Calloway is the most *alive* she has felt since she died, and a soul that has been grey and unseen for ninety years will forgive almost anything, even being beaten, even being eaten, in exchange for being *looked at* like she matters. She is not yet his. But she is, your sense reads, perhaps a month from never wanting to leave — and the only thing that can save her is the one move her whole ordered soul was never taught: to walk away from the one table that finally made her feel seen.)*", onEnter = new[] { new FlagClause { key = "cal.read_auditor", op = FlagOp.SetTrue }, new FlagClause { key = "cal.knows_auditor_trap", op = FlagOp.SetTrue }, new FlagClause { key = "disp.haunted", op = FlagOp.AddInt, amount = 1 } } });
            g.nodes.Add(new DialogueNode { id = "aud_losing", speaker = "the Auditor", text = "*(The question lands, and the armor doesn't so much crack as *sag*, ninety years of grey exhaustion showing through all at once.)* …*am* i *here* to *shut* him *down.* *(a long silence)* …*(barely)* …i was. …*three* *months* *ago*, i *was.* …*(she looks at the framed injunctions, at the comped drink, at her own grey hands)* …he *hasn't* *bribed* me, cold one. i want that *on* the *record* — *no* *coin*, *no* *favor*, *nothing* i could *file.* he *follows* every *rule* i *cite.* *posts* them. *honors* them. and then *smiles* at me *through* the *gaps* and asks if i've *eaten*, because i *forget* to, and — *(her voice drops)* …*nobody* *asks* if i've *eaten*, cold one. i've been *grey* *ninety* *years.* i am a *function.* a *ledger* with *legs.* …and *he* …*(she presses the ledger to her chest)* …*he* *treats* me like a *worthy* *opponent.* like i'm *clever.* like *beating* me is *hard* and *fun* and *worth* *doing* *slowly.* …and i *know* — i *know* it's the *con*, i've *read* the *file* on *Em*, i *know* how this *ends* — …*(she meets your eyes, frightened)* …but *gods* *help* me, cold one …i *don't* *remember* …the *last* *time* …i *wanted* to *win* an *audit* *less.* …*that's* …*that's* the *answer* to your *question*, isn't it. …*am* i still here to *shut* him *down.* …or am i *just* …*here.* …*(barely)* …*i* *don't* *know* *anymore.* …and *that* …*terrifies* me …*more* …than he *does.*", onEnter = new[] { new FlagClause { key = "cal.asked_auditor", op = FlagOp.SetTrue }, new FlagClause { key = "cal.knows_auditor_losing", op = FlagOp.SetTrue }, new FlagClause { key = "disp.haunted", op = FlagOp.AddInt, amount = 1 } } });
            g.nodes.Add(new DialogueNode { id = "aud_returned", speaker = "the Auditor", text = "*(She listens — and as you lay it out, the trap and the one door out of it, the grey exhaustion in her slowly hardens back into something she'd half-forgotten she had: *spine.*)* …*'the* one *audit* …he *can't* *frame.'* *(she breathes)* …*(she looks at the comped drink — and, for the first time in three months, pushes it firmly away)* …you're *right.* …*gods*, you're *right*, and i've *known* it for *weeks* and *called* the *knowing* *thoroughness* — *'one* more *injunction*, one more *clause*, surely *this* one' — when the *truth* is i kept *writing* them …because *writing* them *kept* me *at* his *table.* …*(she straightens, and the ledger becomes a tool again instead of a shield)* …i *cannot* *close* him. …no one *can*, with *law* — he *is* the *law's* *own* *logic*, *taken* *honest*, you said it *exactly.* …but i can *file* the *true* *thing.* …*'this* establishment *cannot* be *closed*, because it is the *Concord's* *own* *trade* …*minus* the *hypocrisy.* …*recommend* …the *order* …*audit* …*itself.''* …*(a wild, grey, exhilarated breath)* …they'll *bury* the *report.* …they'll *grey*-*list* me for *filing* it. …*let* them. …*(she looks at you, ninety years of invisible bookkeeper blazing into one clean act of defiance)* …because the *one* thing, cold one — the *one* thing in *three* *months* — that *Calloway* *cannot* *frame* and *hang* on his *wall* …is an *auditor* who *walks* *out* his *door* …*owing* him *nothing* …having *drunk* *nothing* …and *unbeaten*, because she *stopped* *playing* the *game* he *wins.* …*(she tucks the ledger away, and offers you, stiffly, the first genuine thing she has felt in a century: a smile)* …*thank* you. …i came here to *close* a *devil.* …i'll *leave* …having *closed* …*the* *only* *account* …that *mattered.* …*mine.* …*mind* him, on your way to his *table*, cold one. …and when he *asks* if you've *eaten* … *(her smile sharpens)* …*lie.* …*it's* the *one* *language* …he *can't* *speak.*", onEnter = new[] { new FlagClause { key = "cal.auditor_seen", op = FlagOp.SetTrue }, new FlagClause { key = "cal.auditor_walks", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "disp.honest", op = FlagOp.AddInt, amount = 1 } } });
            g.nodes.Add(new DialogueNode { id = "aud_leave", speaker = "the Auditor", text = "*(She nods, clutching the ledger, and gives you a warning that is also, you sense, a confession.)* …*mind* *yourself* in *there*, cold one. …*(she lowers her voice)* …he'll *be* *honest* with you. that's the — that's the *part* *nobody* *warns* you about. you *brace* for a *liar* and you get a man who tells you the *truth* …*so* *warmly* …*so* *completely* …that you *walk* out having *agreed* to things you'd have *fought* a *liar* over. …*(she glances at the framed injunctions)* …*honesty*, cold one, in the *hands* of a soul *that* *charming* …is the *deadliest* *weapon* in the *dead* *lands.* …i came with *eleven* *injunctions* and *ninety* *years* of *grey* *discipline* …and the *only* *thing* that's *kept* me *standing* …*(barely)* …is that he hasn't, *yet*, *quite*, made me *want* …to *stop* *standing.* …*go* on. …and *count* your *fingers* …after you *shake* his *hand.*" });
            g.nodes.Add(new DialogueNode { id = "cal_aud_lever", speaker = "the Auditor", text = "*(She goes very still. The ledger trembles in her hands. You watch the bookkeeper and the betrayed-something-more war across her grey face, because she understands, instantly and completely, exactly what you are holding.)* …*(barely)* …*gods.* …*that's* — …*that* would *do* it. …*that* would *close* him *forever*, where *eleven* *injunctions* and *ninety* *years* of *discipline* — …*(she swallows)* …his *power* is *credibility*, cold one. you *cut* the *credibility* …and the *whole* *house* …*comes* *down.* …*(she looks at you, and her voice drops)* …a *hundred* souls *freed* of his *markers.* *Em*, *whole* of his *debt.* …the *Concord* *vindicated.* *me* …*vindicated*, after *three* *grey* *months* of *losing.* …*(and then, slowly, the harder thing)* …and *Calloway* …*ruined.* *finished.* the *one* *soul* in the *dead* *lands* …who *wasn't* *afraid* …*made* *afraid*, *at* *last.* …*(she meets your eyes, and lays the choice entirely in your hands)* …it's *yours* to *give*, cold one. …i'll *use* it if you *do* — *gods* *help* me, it's my *job*, and it's *not* even *wrong* — …but i'll *not* *pretend* it's *clean.* …*do* you *hand* it to me? …or did you *learn* that *secret* …only to *keep* it?",
                choices = new[]
                {
                new DialogueChoice { text = "*(give her the lever — ruin him, and free the hundred souls he holds)* \"Use it. He's a predator who keeps souls in chains and calls it generosity, and the hundred he owns are worth more than the one charming man who owns them. Free them. Close the Long Odds. I'll carry what it cost — and it'll cost.\"", nextNodeId = "cal_aud_ruin", effects = new[] { new FlagClause { key = "cal.calloway_ruined", op = FlagOp.SetTrue }, new FlagClause { key = "cal.freed_the_debtors", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "disp.merciful", op = FlagOp.AddInt, amount = 1 }, new FlagClause { key = "disp.ruthless", op = FlagOp.AddInt, amount = 1 } } },
                new DialogueChoice { text = "*(withhold it — some knives you carry precisely so they're never thrown)* \"No. Keep auditing if you must, Auditor — but you won't get this from me. He's a snake, and he showed me his one soft underside trusting I wouldn't bite it. I'm not going to be the soul that ruins a man for the single decent thing he was ashamed of. Walk out clean, like we said. Leave him his secret.\"", nextNodeId = "cal_aud_protect", effects = new[] { new FlagClause { key = "cal.protected_secret", op = FlagOp.SetTrue }, new FlagClause { key = "disp.honest", op = FlagOp.AddInt, amount = 1 }, new FlagClause { key = "disp.merciful", op = FlagOp.AddInt, amount = 1 } } }
                } });
            g.nodes.Add(new DialogueNode { id = "cal_aud_ruin", speaker = "the Auditor", text = "*(She takes it — the secret, the lever, the one true unkillable thing — and you watch ninety grey years of losing turn, in a breath, into the cold clean certainty of a bookkeeper who has finally balanced the impossible account. She does not gloat. She is better than that, and the thing is too large for gloating.)* …*it's* *done*, then. …*(she writes, fast, final)* …i'll *file* it *tonight* — *not* an *injunction*, a *notice*, *posted* to *every* *debtor* in the *house*: *'the* *holder* of your *marker* has *forgiven* *debts* *for* *nothing*; his *paper* is *unsecured*; you may *walk.''* …*(she breathes)* …by *morning* the *Long* *Odds* is *empty.* the *fear* that *filled* it …*gone.* a *hundred* souls …*un*-*chained.* *Em* …*free.* …*(she looks at you, and there is gratitude in it, and grief, and the knowledge that the two will never separate)* …you did a *just* thing, cold one. i want you to *hear* that, because the *next* part is *true* *too*: …you *also* *ended* …the *only* *soul* in this *grey* *country* …who was *not* *afraid* of *anything.* …*(quietly)* …he *trusted* you with the *one* *card* that *kills* him. …and you *played* it …to *free* the *people* he *was* *killing* *slowly.* …*both* of those …are *real*, cold one. …*carry* *both.* …*(she tucks the ledger away, and for the first time in three months, the grey sister is not losing — and does not look as though winning is what she thought it would feel like)* …*thank* you. …i *think.* …*go* on. …and if you *pass* the *Long* *Odds* …*after* — *(barely)* …*don't* *look* *in.* …an *empty* *house* …with the *lamps* *still* *lit* …is a *hard* *thing* …to *un*-*see.*" });
            g.nodes.Add(new DialogueNode { id = "cal_aud_protect", speaker = "the Auditor", text = "*(She lets out a long breath — and it is not disappointment, you realize, but something closer to relief, the relief of a soul spared the weight of the verdict it was sworn to deliver.)* …*(she closes the ledger, gently)* …*no.* …*all* *right.* …*no.* …*(a grey, tired, almost-smile)* …you *know*, cold one, i could *order* you to *surrender* it — *Concord* *authority*, *material* *to* an *open* *audit* — and you'd *tell* me *no*, and we'd *both* *know* i *couldn't* *make* you. …*(she shakes her head)* …*ninety* *years* i've *balanced* *books.* and the *one* time a *ledger* *finally* *balances* in my *favor* …it's because a soul *betrayed* a *confidence* …and you *won't* …and i find …*(barely)* …i find i'm *glad.* …*that* should *trouble* me. …*it* *doesn't.* …*(she straightens, and the old defiance is back, cleaner now)* …i'll *walk* *out* *clean*, like you *said.* file the *true* *report* — *'cannot* be *closed* by *law'* — and let the *Concord* *grey*-*list* me for it. …because *closing* him with a *secret* he was *ashamed* of …*(she meets your eyes)* …*that's* not an *audit*, cold one. *that's* a *mugging* with *letterhead.* …and i did *not* *die* …and stay *honest* *ninety* *years* …to become *that.* …*you* *kept* his *secret.* …*i'll* *keep* my *oath.* …*(the first real warmth she's shown)* …*two* souls …*leaving* his *table* …with their *hands* *clean.* …he'd *hate* it. …*don't* *tell* him. …let him *think* …*everyone's* …for *sale.*" });
            graphs.Add(g);

            return graphs;
        }
    }
